arguments.file_text:
@namespace sv_b51a535450984f4abd63954b62cd58b1.Components.Pages.ApplySteps

<div class="step-indicator">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var stepIndex = i;
        var css = stepIndex == CurrentStep ? "step active"
                : stepIndex < CurrentStep ? "step completed"
                : "step future";

        <div class="@css" @onclick="() => OnStepClick(stepIndex)">
            <div class="step-circle">
                @if (stepIndex < CurrentStep)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <div class="step-label">@StepNames[stepIndex]</div>
        </div>

        @if (i < StepNames.Count - 1)
        {
            <div class="step-connector @(i < CurrentStep ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public List<string> StepNames { get; set; } = [];
    [Parameter] public EventCallback<int> OnNavigate { get; set; }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigate.InvokeAsync(step);
        }
    }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    flex-wrap: wrap;
    gap: 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 100px;
    cursor: default;
}

.step.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
