+                <div class="col-md-4">
+                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
+                    <input type="date" class="form-control" value="@entry.StartDate.ToString("yyyy-MM-dd")"
+                           @onchange="e => UpdateEntry(index, entry with { StartDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : entry.StartDate })" />
+                </div>
+                <div class="col-md-4">
+                    <label class="form-label">End Date</label>
+                    <input type="date" class="form-control" value="@entry.EndDate?.ToString("yyyy-MM-dd")"
+                           disabled="@entry.IsCurrent"
+                           @onchange="e => UpdateEntry(index, entry with { EndDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null })" />
+                </div>
+                <div class="col-md-4 d-flex align-items-end mb-1">
+                    <div class="form-check">
+                        <input class="form-check-input" type="checkbox" checked="@entry.IsCurrent"
+                               @onchange="e => UpdateEntry(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
+                        <label class="form-check-label">Currently working here</label>
+                    </div>
+                </div>
+            </div>
+
+            <div class="mb-2">
+                <label class="form-label">Description</label>
+                <textarea class="form-control" rows="2" value="@entry.Description"
+                          @onchange="e => UpdateEntry(index, entry with { Description = e.Value?.ToString() ?? "" })"></textarea>
+            </div>
+        </div>
+    </div>
+}
+
+<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
+    + Add Another Position
+</button>
+
+@if (ValidationMessage is not null)
+{
+    <div class="alert alert-danger">@ValidationMessage</div>
+}
+
+<div class="d-flex justify-content-between">
+    <button class="btn btn-secondary" @onclick="OnBack">&laquo; Back</button>
+    <button class="btn btn-primary" @onclick="HandleNext">Next &raquo;</button>
+</div>
+
+@code {
+    [Parameter] public List<WorkEntryModel> Entries { get; set; } = [];
+    [Parameter] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
+    [Parameter] public EventCallback OnNext { get; set; }
+    [Parameter] public EventCallback OnBack { get; set; }
+
+    private string? ValidationMessage;
+
+    public class WorkEntryModel
+    {
+        public string Company { get; set; } = "";
+        public string Title { get; set; } = "";
+        public DateTime StartDate { get; set; } = DateTime.Today;
+        public DateTime? EndDate { get; set; }
+        public bool IsCurrent { get; set; }
+        public string Description { get; set; } = "";
+    }
+
+    private void UpdateEntry(int index, WorkEntryModel updated)
+    {
+        Entries[index] = updated;
+    }
+
+    private void AddEntry()
+    {
+        Entries.Add(new WorkEntryModel());
+    }
+
+    private void RemoveEntry(int index)
+    {
+        if (Entries.Count > 1)
+        {
+            Entries.RemoveAt(index);
+        }
+    }
+
+    private async Task HandleNext()
+    {
+        ValidationMessage = null;
+
+        foreach (var entry in Entries)
+        {
+            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
+            {
+                ValidationMessage = "Company name and job title are required for all entries.";
+                return;
+            }
+        }
+
+        await EntriesChanged.InvokeAsync(Entries);
+        await OnNext.InvokeAsync();
+    }
+}
+

