@page "/apply"
@using sv_b51a535450984f4abd63954b62cd58b1.Components.Pages.ApplySteps
@using sv_b51a535450984f4abd63954b62cd58b1.Models
@using sv_b51a535450984f4abd63954b62cd58b1.Services
@using static sv_b51a535450984f4abd63954b62cd58b1.Components.Pages.ApplySteps.WorkHistoryStep
@using static sv_b51a535450984f4abd63954b62cd58b1.Components.Pages.ApplySteps.ReferencesStep
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" StepNames="stepNames" OnNavigate="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep
                @bind-FullName="fullName"
                @bind-Email="email"
                @bind-Phone="phone"
                @bind-Address="address"
                ValidateEmail="ApplicationService.ValidateEmailAsync"
                OnNext="NextStep" />
            break;

        case 1:
            <WorkHistoryStep
                @bind-Entries="workEntries"
                OnNext="NextStep"
                OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep
                @bind-References="references"
                OnNext="NextStep"
                OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep
                @bind-CoverLetter="coverLetter"
                OnNext="NextStep"
                OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep
                FullName="@fullName"
                Email="@email"
                Phone="@phone"
                Address="@address"
                WorkEntries="workEntries"
                References="references"
                CoverLetter="@coverLetter"
                OnBack="PreviousStep"
                OnEdit="GoToStep"
                OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep;

    private readonly List<string> stepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    // Step 1 state
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2 state
    private List<WorkEntryModel> workEntries = [new()];

    // Step 3 state
    private List<ReferenceModel> references = [new(), new()];

    // Step 4 state
    private string coverLetter = "";

    private void NextStep() => currentStep = Math.Min(currentStep + 1, stepNames.Count - 1);
    private void PreviousStep() => currentStep = Math.Max(currentStep - 1, 0);
    private void GoToStep(int step) => currentStep = step;

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(
            new PersonalInfo(fullName, email, phone, address),
            new WorkHistory(workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate, e.EndDate, e.Description)).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

